// Merge the career advanced sidecar (NBA + CBB rate stats from Sports Reference)
// into each historical prospect at module load. This keeps the JSON file the
// single source of truth for the existing fields and lets the advanced sidecar
// be regenerated independently via scripts/ingestion/enrich-historical-advanced.js.
const HISTORICAL_PROSPECTS = HISTORICAL_PROSPECTS_RAW.map((entry) => ({
  ...entry,
  nbaAdv: HISTORICAL_ADVANCED_STATS[entry.id]?.nbaAdv || null,
  cbbAdv: HISTORICAL_ADVANCED_STATS[entry.id]?.cbbAdv || null,
}));

const ARCHETYPE_BY_NAME = (() => {
  const map = new Map();
  for (const arch of ARCHETYPE_CATALOG.archetypes || []) map.set(arch.name, arch);
  return map;
})();

function getArchetypeMeta(archetypeName) {
  return ARCHETYPE_BY_NAME.get(archetypeName) || null;
}

// Returns a color used as the leading "family bar" on every prospect row
// (Big Board + My Board). Uniques → brand purple, Star tier → orange,
// everything else maps from position family. This is the PROSPERA visual
// signature on board surfaces.
function familyBarColor(p) {
  const archetypeMeta = ARCHETYPE_BY_NAME.get(p.archetype) || null;
  const isUnique = archetypeMeta?.tier === "Unique";
  if (isUnique) return "#A855F7"; // purple
  if (archetypeMeta?.tier === "Star") return "#F97316"; // brand orange
  const pos = String(p.pos || "");
  const pos2 = String(p.pos2 || "");
  if (pos.includes("PG") || pos2.includes("PG") || pos.includes("SG") || pos2.includes("SG")) return "#3B82F6"; // guard → blue
  if (pos.includes("SF") || pos2.includes("SF") || pos.includes("PF") || pos2.includes("PF")) return "#10B981"; // wing → green
  return "#F59E0B"; // big → amber
}

// Lookup key into profileStats.json — matches the file's slug convention:
// lowercase, remove anything that isn't a letter or digit.
function profileStatsKey(name) {
  return String(name || "").toLowerCase().replace(/[^a-z0-9]/g, "");
}

// Look up the rich per-prospect stats blob from profileStats.json. Returns null
// if no record exists (for international prospects without NCAA data, etc.).
//
// Also merges in the advanced-extras sidecar (STL%, BLK%, OBPM, DBPM, PER,
// ORB%, DRB%, 3PAr) generated by import-prospect-advanced-extras.js. The
// extras live alongside profileStats so they can be regenerated from a
// fresh Stathead pull without rewriting the canonical profileStats.json.
function getProspectStats(prospect) {
  if (!prospect?.name) return null;
  const key = profileStatsKey(prospect.name);
  const base = PROFILE_STATS[key];
  if (!base) return null;
  const extras = PROSPECT_ADVANCED_EXTRAS[key];
  if (!extras) return base;
  // Merge: extras fields fill gaps in base.stats.advanced. Extras don't
  // overwrite values the base already has (TS%, eFG%, USG% etc. all stay
  // canonical from profileStats).
  const baseAdv = base.stats?.advanced || {};
  const mergedAdv = {
    ...baseAdv,
    stlPct:    baseAdv.stlPct    ?? extras.stlPct,
    blkPct:    baseAdv.blkPct    ?? extras.blkPct,
    obpm:      baseAdv.obpm      ?? extras.obpm,
    dbpm:      baseAdv.dbpm      ?? extras.dbpm,
    per:       baseAdv.per       ?? extras.per,
    orbPct:    baseAdv.orbPct    ?? extras.orbPct,
    drbPct:    baseAdv.drbPct    ?? extras.drbPct,
    threePAr:  baseAdv.threePAr  ?? extras.threePAr,
    ftr:       baseAdv.ftr       ?? extras.ftr,
    pfr:       baseAdv.pfr       ?? extras.pfr,
  };
  return {
    ...base,
    stats: {
      ...base.stats,
      advanced: mergedAdv,
    },
  };
}

// Derive a counting line scaled to N minutes (per-36) or N possessions (per-100).
// Pace is unknown for college rosters, so per-100 uses a 70-poss approximation
// that matches typical NCAA pace; flagged in the UI as "approx" so users
// don't read the exact decimals as gospel.
function deriveScaledLine(season, n) {
  if (!season || !season.minutes || season.minutes <= 0) return null;
  const factor = n / season.minutes;
  const scale = (v) => (typeof v === "number" ? Math.round(v * factor * 10) / 10 : null);
  return {
    pts: scale(season.points),
    reb: scale(season.rebounds),
    ast: scale(season.assists),
    stl: scale(season.steals),
    blk: scale(season.blocks),
    tov: scale(season.turnovers),
  };
}

// Per-100 approximation. Multiplies per-36 by ~100/70 (typical NCAA pace);
// adequate accuracy for cross-prospect comparison, not a "real" per-100.
function derivePer100Approx(season) {
  if (!season || !season.minutes) return null;
  const per36 = deriveScaledLine(season, 36);
  if (!per36) return null;
  const k = 100 / 70;
  const scale = (v) => (typeof v === "number" ? Math.round(v * k * 10) / 10 : null);
  return {
    pts: scale(per36.pts),
    reb: scale(per36.reb),
    ast: scale(per36.ast),
    stl: scale(per36.stl),
    blk: scale(per36.blk),
    tov: scale(per36.tov),
  };
}

// =============================================================================
// COMPARABLES SIMILARITY ENGINE
// =============================================================================
// Replaces the old "position + height + archetype-label string match" heuristic.
// Builds a feature vector for each prospect (current + historical) using the
// rich CBB advanced data we ingested, computes a weighted Euclidean distance
// in z-space, and converts that to a 0-100 similarity score.
//
// 8 features used, all available on both sides:
//   height (in)   — physical foundation
//   USG%          — creator load (primary signal of role)
//   AST%          — playmaking volume
//   TOV%          — mistake rate
//   TRB%          — rebounding share (position-relative)
//   BPM           — overall college impact
//   ORtg          — offensive efficiency
//   DRtg          — defensive efficiency
//
// Feature weights tuned so the scout's instinct lines up with the math:
//   height + USG + BPM dominate (the things you'd notice first on a card),
//   ORtg/DRtg/TOV are tiebreakers within similar profiles.
// =============================================================================

const COMP_FEATURE_WEIGHTS = {
  height: 3.0,
  usg:    2.5,
  bpm:    2.5,
  ast:    2.0,
  trb:    1.5,
  tov:    1.0,
  ortg:   1.0,
  drtg:   1.0,
};
const COMP_FEATURE_KEYS = Object.keys(COMP_FEATURE_WEIGHTS);

// Pull a numeric feature from a CURRENT prospect's profileStats record.
// Returns null when missing — caller substitutes the cohort mean (z=0).
function extractCurrentFeatures(prospect) {
  if (!prospect) return null;
  const slug = profileStatsKey(prospect.name);
  const ps = PROFILE_STATS[slug];
  const adv = ps?.stats?.advanced;
  if (!adv) return null;
  const parsePct = (v) => (v == null ? null : parseFloat(String(v).replace("%", "")));
  return {
    height: heightToInches(prospect.height),
    usg:    parsePct(adv.usage),
    ast:    parsePct(adv.assistRate),
    tov:    parsePct(adv.turnoverRate),
    trb:    parsePct(adv.reboundRate),
    bpm:    typeof adv.bpm  === "number" ? adv.bpm  : null,
    ortg:   typeof adv.ortg === "number" ? adv.ortg : null,
    drtg:   typeof adv.drtg === "number" ? adv.drtg : null,
  };
}

// Pull the same feature shape from a HISTORICAL's cbbAdv block.
function extractHistoricalFeatures(historical) {
  if (!historical?.cbbAdv) return null;
  const c = historical.cbbAdv;
  return {
    height: heightToInches(historical.height),
    usg:    typeof c.usgPct === "number" ? c.usgPct : null,
    ast:    typeof c.astPct === "number" ? c.astPct : null,
    tov:    typeof c.tovPct === "number" ? c.tovPct : null,
    trb:    typeof c.trbPct === "number" ? c.trbPct : null,
    bpm:    typeof c.bpm    === "number" ? c.bpm    : null,
    ortg:   typeof c.ortg   === "number" ? c.ortg   : null,
    drtg:   typeof c.drtg   === "number" ? c.drtg   : null,
  };
}

// Cohort mean / std per feature, computed once at module load. Used to
// z-score the feature vectors before computing similarity. Only historicals
// with cbbAdv data participate (~74% of the archive — the rest are filtered
// out as comp candidates entirely since we have nothing to compare against).
const COMP_FEATURE_STATS = (() => {
  const out = {};
  for (const key of COMP_FEATURE_KEYS) {
    const values = [];
    for (const h of HISTORICAL_PROSPECTS) {
      const f = extractHistoricalFeatures(h);
      if (!f) continue;
      const v = f[key];
      if (typeof v === "number" && Number.isFinite(v)) values.push(v);
    }
    if (values.length === 0) {
      out[key] = { mean: 0, std: 1 };
      continue;
    }
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const variance = values.reduce((a, b) => a + (b - mean) ** 2, 0) / values.length;
    const std = Math.sqrt(variance) || 1;
    out[key] = { mean, std };
  }
  return out;
})();

// Convert raw feature object → z-score vector. Missing features → 0 (mean).
function toZVector(features) {
  if (!features) return null;
  return COMP_FEATURE_KEYS.map((key) => {
    const v = features[key];
    if (v == null || !Number.isFinite(v)) return 0;
    const { mean, std } = COMP_FEATURE_STATS[key];
    return (v - mean) / std;
  });
}

// Weighted Euclidean distance between two z-vectors. Lower = more similar.
function weightedDistance(za, zb) {
  let sum = 0;
  for (let i = 0; i < COMP_FEATURE_KEYS.length; i++) {
    const w = COMP_FEATURE_WEIGHTS[COMP_FEATURE_KEYS[i]];
    const d = za[i] - zb[i];
    sum += w * d * d;
  }
  return Math.sqrt(sum);
}

// Distance → 0-100 similarity score. Tuned so:
//   distance 0     → 100 (identical profile)
//   distance ~1.5  → ~85 (clearly similar)
//   distance ~3    → ~65 (passable comp)
//   distance ~5    → ~40 (loose match)
//   distance >7    → ~20 (probably noise)
function distanceToSimilarity(d) {
  return Math.round(100 * Math.exp(-d * 0.18));
}

function isUniqueArchetype(archetypeName) {
  const meta = getArchetypeMeta(archetypeName);
  return Boolean(meta && meta.tier === "Unique");
}
