// =============================================================================
// ACTIVE CLASS FILTER · 2026 Big Board cohort
// =============================================================================
// PROSPECTS_ALL holds the full inline archive (every prospect we have data for,
// preserved for the 2027 transition or later re-activation). PROSPECTS — what
// the UI actually consumes — is filtered to only the entries flagged active in
// `prospectAliases.json`. Inactive prospects keep their cards / stats / notes
// in the data layer but don't render anywhere.
//
// To roll into the 2027 cycle: edit prospectAliases.json — flip the 2026
// entries to active=false (or replace them outright with 2027 prospects).
// All UI surfaces inherit the new active set automatically.
const ACTIVE_PROSPECT_NAME_SLUGS = new Set(
  (PROSPECT_ALIASES.entries || [])
    .filter((e) => e.active !== false)
    .map((e) => String(e.name || "").toLowerCase().replace(/[^a-z0-9]/g, ""))
);
const PROSPECTS = PROSPECTS_ALL.filter((p) =>
  ACTIVE_PROSPECT_NAME_SLUGS.has(String(p.name || "").toLowerCase().replace(/[^a-z0-9]/g, ""))
);

// =============================================================================
// COHORT PERCENTILES — computed once at module load.
// For every prospect with stats in profileStats.json, we pre-scale their
// counting line to per-game / per-36 / per-100 and rank them across the
// cohort for each individual stat. Lookup lives in COHORT_PERCENTILES, keyed
// by `${prospectId}.${rateMode}.${statKey}` for counting and
// `${prospectId}.advanced.${statKey}` for the advanced metrics.
//
// Inverted stats (TOV, turnoverRate, drtg) are flipped so "higher percentile
// always means BETTER" — UI can use one color rule across the board.
// Trait-score distribution across the active class. The raw 5-bucket scores
// (Scoring, Playmaking, Defense, Feel, Athleticism) cluster in the 50-80
// range — they're derived from 1-10 trait grades and only hit 80 when a
// player has 8/10 across the bucket inputs.
//
// Grade thresholds combine TWO criteria so A+ requires BOTH:
//   1. Class rank (top 5% / 15% / 40% / 75% / bottom 25%)
//   2. Absolute value floor (78+ for A+, 68+ for A)
//
// The class-rank piece keeps grading honest within the current class; the
// absolute floor prevents a weak class from getting handed A+ for a 70.
// Floor calibrated against historical NBA-prospect-grade conventions:
// 78+ across a trait bucket means 8/10 average across its components,
// which scout-traditionally lands in the "top draft prospect" range.
//
// Tightened from a previous "top 10% = A+" version that the user called
// out as too generous — A+ should be earned, not class-handed.
const TRAIT_GRADE_FLOORS = {
  // A+ requires hitting both the cohort percentile AND this absolute value.
  // Ensures a 70 in a weak class doesn't get an A+ just for being top of class.
  aPlusFloor: 78,
  aFloor:     68,
};

const TRAIT_COHORT_THRESHOLDS = (() => {
  const traits = ["Scoring", "Playmaking", "Defense", "Feel", "Athleticism"];
  const out = {};
  for (const trait of traits) {
    const vals = PROSPECTS
      .map((p) => p.traits?.[trait])
      .filter((v) => typeof v === "number")
      .sort((a, b) => b - a); // descending
    if (vals.length === 0) {
      out[trait] = { aPlusMin: 90, aMin: 78, bMin: 60, cMin: 50 };
      continue;
    }
    const pct = (p) => vals[Math.min(vals.length - 1, Math.floor(vals.length * p))];
    out[trait] = {
      aPlusMin:  pct(0.05),  // top 5% of class
      aMin:      pct(0.15),  // top 15%
      bMin:      pct(0.40),  // top 40%
      cMin:      pct(0.75),  // top 75% — below this = D
    };
  }
  return out;
})();

const COHORT_PERCENTILES = (() => {
  // Build per-prospect scaled stat lines once
  const cohort = [];
  for (const p of PROSPECTS) {
    const slug = String(p.name || "").toLowerCase().replace(/[^a-z0-9]/g, "");
    const stats = PROFILE_STATS[slug];
    if (!stats?.stats) continue;
    const season = stats.stats.season;
    // Merge advanced + extras the same way getProspectStats does, so cohort
    // percentiles can rank STL%/BLK%/OBPM/DBPM/PER/3PAr alongside the older
    // stats. Extras only fill missing fields.
    const baseAdv = stats.stats.advanced || {};
    const extras = PROSPECT_ADVANCED_EXTRAS[slug] || {};
    const advanced = {
      ...baseAdv,
      stlPct:    baseAdv.stlPct    ?? extras.stlPct,
      blkPct:    baseAdv.blkPct    ?? extras.blkPct,
      obpm:      baseAdv.obpm      ?? extras.obpm,
      dbpm:      baseAdv.dbpm      ?? extras.dbpm,
      per:       baseAdv.per       ?? extras.per,
      orbPct:    baseAdv.orbPct    ?? extras.orbPct,
      drbPct:    baseAdv.drbPct    ?? extras.drbPct,
      threePAr:  baseAdv.threePAr  ?? extras.threePAr,
      ftr:       baseAdv.ftr       ?? extras.ftr,
      pfr:       baseAdv.pfr       ?? extras.pfr,
    };
    if (!season) continue;
    const factor36 = season.minutes > 0 ? 36 / season.minutes : null;
    const factor100 = season.minutes > 0 ? (36 / season.minutes) * (100 / 70) : null;
    const scale = (v, k) => (typeof v === "number" && k != null ? Math.round(v * k * 10) / 10 : null);
    // Derived: AST/TO ratio — uncovered scout signal we can compute now.
    const astToRatio = (typeof season.assists === "number" && typeof season.turnovers === "number" && season.turnovers > 0)
      ? Math.round((season.assists / season.turnovers) * 100) / 100
      : null;
    cohort.push({
      id: p.id,
      perGame: {
        pts: season.points ?? null,
        reb: season.rebounds ?? null,
        ast: season.assists ?? null,
        stl: season.steals ?? null,
        blk: season.blocks ?? null,
        tov: season.turnovers ?? null,
        astTo: astToRatio,
      },
      per36: factor36 ? {
        pts: scale(season.points, factor36),
        reb: scale(season.rebounds, factor36),
        ast: scale(season.assists, factor36),
        stl: scale(season.steals, factor36),
        blk: scale(season.blocks, factor36),
        tov: scale(season.turnovers, factor36),
        astTo: astToRatio,  // ratio is rate-invariant
      } : null,
      per100: factor100 ? {
        pts: scale(season.points, factor100),
        reb: scale(season.rebounds, factor100),
        ast: scale(season.assists, factor100),
        stl: scale(season.steals, factor100),
        blk: scale(season.blocks, factor100),
        tov: scale(season.turnovers, factor100),
        astTo: astToRatio,
      } : null,
      advanced: advanced ? {
        trueShooting: advanced.trueShooting ? parseFloat(String(advanced.trueShooting).replace("%", "")) : null,
        efgPct:       advanced.efgPct       ? parseFloat(String(advanced.efgPct).replace("%", ""))       : null,
        usage:        advanced.usage        ? parseFloat(String(advanced.usage).replace("%", ""))        : null,
        assistRate:   advanced.assistRate   ? parseFloat(String(advanced.assistRate).replace("%", ""))   : null,
        turnoverRate: advanced.turnoverRate ? parseFloat(String(advanced.turnoverRate).replace("%", "")) : null,
        reboundRate:  advanced.reboundRate  ? parseFloat(String(advanced.reboundRate).replace("%", ""))  : null,
        ortg:         typeof advanced.ortg  === "number" ? advanced.ortg : null,
        drtg:         typeof advanced.drtg  === "number" ? advanced.drtg : null,
        bpm:          typeof advanced.bpm   === "number" ? advanced.bpm  : null,
        fgPct:        typeof advanced.fgPct === "number" ? advanced.fgPct * 100 : null,
        threePct:     typeof advanced.threePct === "number" ? advanced.threePct * 100 : null,
        ftPct:        typeof advanced.ftPct === "number" ? advanced.ftPct * 100 : null,
        // New fields from prospectAdvancedExtras (Stathead current-active pull)
        stlPct:       typeof advanced.stlPct === "number" ? advanced.stlPct : null,
        blkPct:       typeof advanced.blkPct === "number" ? advanced.blkPct : null,
        obpm:         typeof advanced.obpm   === "number" ? advanced.obpm   : null,
        dbpm:         typeof advanced.dbpm   === "number" ? advanced.dbpm   : null,
        per:          typeof advanced.per    === "number" ? advanced.per    : null,
        orbPct:       typeof advanced.orbPct === "number" ? advanced.orbPct : null,
        drbPct:       typeof advanced.drbPct === "number" ? advanced.drbPct : null,
        threePAr:     typeof advanced.threePAr === "number" ? advanced.threePAr : null,
        ftr:          typeof advanced.ftr === "number" ? advanced.ftr : null,
        pfr:          typeof advanced.pfr === "number" ? advanced.pfr : null,
      } : null,
    });
  }

  // Each tuple: [group, key, invert]. Invert = true means LOWER raw value
  // ranks higher (TOV, DRtg). Higher percentile always means "better."
  const STAT_DEFS = [
    ["perGame",  "pts", false], ["perGame",  "reb", false], ["perGame",  "ast", false],
    ["perGame",  "stl", false], ["perGame",  "blk", false], ["perGame",  "tov", true],
    ["perGame",  "astTo", false],
    ["per36",    "pts", false], ["per36",    "reb", false], ["per36",    "ast", false],
    ["per36",    "stl", false], ["per36",    "blk", false], ["per36",    "tov", true],
    ["per36",    "astTo", false],
    ["per100",   "pts", false], ["per100",   "reb", false], ["per100",   "ast", false],
    ["per100",   "stl", false], ["per100",   "blk", false], ["per100",   "tov", true],
    ["per100",   "astTo", false],
    ["advanced", "trueShooting", false], ["advanced", "efgPct", false],
    ["advanced", "usage",        false], ["advanced", "assistRate", false],
    ["advanced", "turnoverRate", true ], ["advanced", "reboundRate", false],
    ["advanced", "ortg",         false], ["advanced", "drtg",        true ],
    ["advanced", "bpm",          false],
    ["advanced", "fgPct",        false], ["advanced", "threePct",    false],
    ["advanced", "ftPct",        false],
    // New fields from prospectAdvancedExtras
    ["advanced", "stlPct",       false], ["advanced", "blkPct",      false],
    ["advanced", "obpm",         false], ["advanced", "dbpm",        false],
    ["advanced", "per",          false],
    ["advanced", "orbPct",       false], ["advanced", "drbPct",      false],
    ["advanced", "threePAr",     false],
    ["advanced", "ftr",          false],   // higher = more aggressive
    ["advanced", "pfr",          true ],   // INVERTED — fewer fouls is better
  ];

  const out = {};
  for (const [group, key, invert] of STAT_DEFS) {
    const vals = cohort
      .map((c) => ({ id: c.id, v: c[group]?.[key] }))
      .filter((x) => typeof x.v === "number" && Number.isFinite(x.v));
    if (vals.length < 5) continue;
    for (const entry of vals) {
      const below = vals.filter((x) => x.v < entry.v).length;
      const same  = vals.filter((x) => x.v === entry.v).length;
      // Mid-rank percentile to handle ties fairly
      const raw = (below + same / 2) / vals.length;
      const pct = Math.round((invert ? 1 - raw : raw) * 100);
      const k = `${group}.${key}`;
      if (!out[entry.id]) out[entry.id] = {};
      out[entry.id][k] = Math.max(0, Math.min(100, pct));
    }
  }
  return out;
})();

// Maps the display label used in AdvancedTable to its percentile lookup key.
// Keys NOT in this map render without a percentile indicator (e.g., HT/WT).
const STAT_LABEL_TO_PCT_KEY = {
  // counting line — same pct key under each rate mode (resolved at call site)
  PTS: "pts", PPG: "pts",
  REB: "reb", RPG: "reb",
  AST: "ast", APG: "ast",
  STL: "stl", SPG: "stl",
  BLK: "blk", BPG: "blk",
  TOV: "tov",
  // advanced
  "TS%": "advanced.trueShooting",
  "eFG%": "advanced.efgPct",
  "USG%": "advanced.usage",
  "AST%": "advanced.assistRate",
  "TOV%": "advanced.turnoverRate",
  "REB%": "advanced.reboundRate",
  "ORtg": "advanced.ortg",
  "DRtg": "advanced.drtg",
  "BPM":  "advanced.bpm",
  // splits
  "FG%": "advanced.fgPct",
  "3P%": "advanced.threePct",
  "FT%": "advanced.ftPct",
  // New stats from prospectAdvancedExtras
  "STL%":  "advanced.stlPct",
  "BLK%":  "advanced.blkPct",
  "OBPM":  "advanced.obpm",
  "DBPM":  "advanced.dbpm",
  "PER":   "advanced.per",
  "ORB%":  "advanced.orbPct",
  "DRB%":  "advanced.drbPct",
  "3PAr":  "advanced.threePAr",
  "FTr":   "advanced.ftr",
  "PFr":   "advanced.pfr",
  // Derived
  "AST/TO": "astTo",  // resolved against the per-game bucket via buildPercentileMap
};

// Build a percentile lookup map for a given prospect + rate mode, keyed by
// the visible stat label. Counting-line labels are resolved against the
// rate-mode-specific bucket so toggling PG/36/100 changes the indicators.
function buildPercentileMap(prospectId, rateMode = "perGame") {
  const all = COHORT_PERCENTILES[prospectId];
  if (!all) return {};
  const out = {};
  for (const [label, mapTarget] of Object.entries(STAT_LABEL_TO_PCT_KEY)) {
    if (mapTarget.includes(".")) {
      out[label] = all[mapTarget] ?? null;
    } else {
      // counting stat → resolve against the active rate mode
      const key = `${rateMode}.${mapTarget}`;
      out[label] = all[key] ?? null;
    }
  }
  return out;
}

// ---------- ATOMS ----------
function deriveStory(p) {
  if (!p.traits9 || Object.keys(p.traits9).length === 0) {
    return `${p.name} — ${p.archetype}. ${p.school || "—"}, ${p.cls || ""}. Stat coverage limited; evaluation lean.`;
  }
  const sorted = Object.entries(p.traits9).sort((a, b) => b[1] - a[1]);
  const topTraits = sorted.slice(0, 2);
  const bottomTrait = sorted[sorted.length - 1];
  const flagged = (p.flags || []).length;
  const heightPhrase = p.height && p.wingspan ? `${p.height} / ${p.wingspan}` : (p.height || "");
  const classPhrase = p.cls === "Fr." ? "true freshman" : p.cls === "So." ? "sophomore" : p.cls === "Jr." ? "junior" : p.cls === "Sr." ? "upperclassman" : "international prospect";

  // Lookup archetype meta from the catalog. If found, lean on the catalog's
  // scouting blurb + exemplars. Otherwise fall back to the legacy tier phrase.
  const archetypeMeta = getArchetypeMeta(p.archetype);
  const isUnique = isUniqueArchetype(p.archetype);

  const parts = [];
  parts.push(`${heightPhrase} ${classPhrase} from ${p.school}.`);

  if (archetypeMeta?.notes) {
    // Use the catalog's scouting blurb verbatim (e.g., "Versatile defender,
    // secondary scorer, high-feel team player").
    parts.push(`${p.archetype} prototype — ${archetypeMeta.notes.toLowerCase()}.`);
  } else if (p.archetype) {
    parts.push(`Profiles as a ${p.archetype}.`);
  }

  if (archetypeMeta?.exemplars?.length > 0) {
    const examples = archetypeMeta.exemplars.slice(0, isUnique ? 1 : 2).join(" / ");
    parts.push(`${isUnique ? "Compares only to" : "Comp range:"} ${examples}.`);
  }

  if (topTraits.length >= 2) {
    parts.push(`Top traits: ${topTraits[0][0]} ${topTraits[0][1]}/10, ${topTraits[1][0]} ${topTraits[1][1]}/10.`);
  }

  if (bottomTrait && bottomTrait[1] <= 4) {
    parts.push(`Concern: ${bottomTrait[0]} only ${bottomTrait[1]}/10.`);
  }

  if (flagged > 0) {
    parts.push(`${flagged} active risk flag${flagged > 1 ? "s" : ""}.`);
  }

  return parts.join(" ");
}

