const TraitsTab = ({ p }) => {
  const { displayScore } = useCustomWeights();
  // Risks treat 0=Clean, 1=Watch, 2=Real Risk, 3=Critical (deep dive scale)
  // Legacy data uses 0/1 (clean/flagged). Anything >=1 is "flagged" for the panel.
  const flaggedRisks = Object.entries(p.risks || {}).filter(([, v]) => Number(v) >= 1);
  const cleanRisks = Object.entries(p.risks || {}).filter(([, v]) => Number(v) === 0);
  const overrides = p.__scoutOverrides || { traits: {}, risks: {} };

  // ------------------------------------------------------------------
  // Source new engine values when available. Fall back to authored.
  // ------------------------------------------------------------------
  const computed = useMemo(() => {
    if (!p?.name) return null;
    return getProspectScoresByName(p.name);
  }, [p?.name]);

  // 8-trait (1-10 scale used by the bar) — derived from new engine 0-100
  const effectiveTraits9 = useMemo(() => {
    if (computed?.traits) {
      const out = {};
      const keyMap = {
        "Advantage Creation": "AdvantageCreation",
        "Decision Making":    "DecisionMaking",
        "Passing Creation":   "PassingCreation",
        "Shooting Gravity":   "ShootingGravity",
        "Off-Ball Value":     "OffBallValue",
        "Processing Speed":   "ProcessingSpeed",
        "Scalability":        "Scalability",
        "Defensive Versatility": "DefensiveVersatility",
      };
      let any = false;
      for (const [label, k] of Object.entries(keyMap)) {
        const t = computed.traits[k];
        if (t?.score != null) {
          out[label] = Math.max(1, Math.min(10, Math.round(t.score / 10)));
          any = true;
        }
      }
      if (any) return out;
    }
    return p.traits9 || {};
  }, [computed, p?.traits9]);

  // (The effectiveTraits5 memo that derived a 5-bucket Scoring/Playmaking/
  // Defense/Feel/Athleticism view was deleted when the 5-Bucket Snapshot
  // panel was removed from this tab — see commit notes for the dedup pass.)
  return (
    <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 16 }} className="prospera-eval-grid">
      <div style={{ display: "grid", gap: 16 }}>
        <Section title="Trait Profile">
          <div style={{ ...mono, fontSize: 9, color: T.textMute, letterSpacing: "0.12em", marginBottom: 14 }}>
            8-AXIS EVALUATION TAXONOMY · 1–10 SCALE
          </div>
          {Object.keys(effectiveTraits9).length === 0 ? (
            <div style={{ fontSize: 12, color: T.textMute }}>No trait evaluation on file.</div>
          ) : (() => {
            // Split into offence / defence groups so the shape of the
            // prospect (offense-leaning vs defense-leaning) reads at a glance.
            // Bars are colour-coded by group — cyan for O, signal for D.
            const OFFENSE = ["Advantage Creation", "Shooting Gravity", "Passing Creation", "Off-Ball Value"];
            const DEFENSE = ["Defensive Versatility", "Scalability", "Processing Speed", "Decision Making"];

            const renderRow = (k, color) => {
              const v = effectiveTraits9[k];
              if (v == null) return null;
              const ovr = overrides.traits[k];
              return (
                <div key={k}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8, gap: 8, flexWrap: "wrap" }}>
                    <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ fontSize: 16, color: T.text, fontWeight: 600, letterSpacing: "-0.005em" }}>{k}</span>
                      {ovr && (
                        <span
                          title={`Scout override: was ${ovr.system}/10, set to ${ovr.scout}/10`}
                          style={{
                            ...mono,
                            fontSize: 8,
                            letterSpacing: "0.14em",
                            color: T.cyan,
                            border: `1px solid ${T.cyan}`,
                            padding: "1px 5px",
                            textTransform: "uppercase",
                            fontWeight: 600,
                          }}
                        >
                          Scout
                        </span>
                      )}
                    </span>
                    <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      {ovr && ovr.system != null && (
                        <span
                          style={{ ...mono, fontSize: 10, color: T.textMute, textDecoration: "line-through" }}
                          title="Original system value"
                        >
                          {ovr.system}/10
                        </span>
                      )}
                      <span style={{ ...mono, fontSize: 17, color, fontWeight: 700, letterSpacing: "0.02em" }}>{v} / 10</span>
                    </span>
                  </div>
                  <MetricBar value={v * 10} color={color} />
                </div>
              );
            };

            const groupHeader = (label, color) => (
              <div
                style={{
                  ...mono,
                  fontSize: 11,
                  letterSpacing: "0.22em",
                  color,
                  textTransform: "uppercase",
                  fontWeight: 800,
                  marginBottom: 14,
                  paddingBottom: 6,
                  borderBottom: `1px solid color-mix(in srgb, ${color} 35%, transparent)`,
                }}
              >
                {label}
              </div>
            );

            return (
              <div style={{ display: "grid", gap: 22 }}>
                <div>
                  {groupHeader("Offence", T.cyan)}
                  <div style={{ display: "grid", gap: 16 }}>
                    {OFFENSE.map((k) => renderRow(k, T.cyan))}
                  </div>
                </div>
                <div>
                  {groupHeader("Defence", T.signal)}
                  <div style={{ display: "grid", gap: 16 }}>
                    {DEFENSE.map((k) => renderRow(k, T.signal))}
                  </div>
                </div>
              </div>
            );
          })()}
        </Section>

        {/* The 5-Bucket Snapshot panel that used to live here (Scoring /
            Playmaking / Defense / Feel / Athleticism on a 0-100 scale) was
            a derived / coarser view of the same data the 9-Trait Profile
            already shows above on the 1-10 scale. Two views of the same
            taxonomy was the main source of "I keep seeing this twice"
            feedback — removed. The 9-Trait Profile is now canonical. */}
      </div>

      <div style={{ display: "grid", gap: 16 }}>
        <Section title="Risk Profile">
          <div style={{ ...mono, fontSize: 9, color: T.textMute, letterSpacing: "0.12em", marginBottom: 12 }}>
            8-DIMENSION RISK TAXONOMY
          </div>
          <div style={{ display: "grid", gap: 6 }}>
            {flaggedRisks.length === 0 && (
              <div style={{ fontSize: 12, color: T.textMute }}>No active risks flagged.</div>
            )}
            {flaggedRisks.map(([k, val]) => {
              const ovr = overrides.risks[k];
              const sev = Number(val);
              const sevColor = sev >= 3 ? T.danger : sev >= 2 ? T.warn : T.cyan;
              const sevLabel = sev >= 3 ? "CRITICAL" : sev >= 2 ? "REAL RISK" : "WATCH";
              return (
                <div key={k} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 10px", borderTop: `1px solid ${T.borderSoft}`, borderRight: `1px solid ${T.borderSoft}`, borderBottom: `1px solid ${T.borderSoft}`, borderLeft: `2px solid ${sevColor}`, flexWrap: "wrap" }}>
                  <AlertTriangle size={12} color={sevColor} />
                  <span style={{ fontSize: 12, color: T.text }}>{k}</span>
                  {ovr && (
                    <span
                      title={`Scout override: was ${ovr.system ?? "—"}, set to ${ovr.scout}`}
                      style={{
                        ...mono,
                        fontSize: 8,
                        letterSpacing: "0.14em",
                        color: T.cyan,
                        border: `1px solid ${T.cyan}`,
                        padding: "1px 5px",
                        textTransform: "uppercase",
                        fontWeight: 600,
                      }}
                    >
                      Scout
                    </span>
                  )}
                  <span style={{ flex: 1 }} />
                  <span style={{ ...mono, fontSize: 9, color: sevColor, letterSpacing: "0.1em" }}>{sevLabel}</span>
                </div>
              );
            })}
          </div>
          {cleanRisks.length > 0 && (
            <div style={{ marginTop: 14, paddingTop: 14, borderTop: `1px solid ${T.borderSoft}` }}>
              <div style={{ ...mono, fontSize: 9, color: T.textMute, letterSpacing: "0.1em", marginBottom: 8 }}>CLEAR</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                {cleanRisks.map(([k]) => (
                  <span key={k} style={{ ...mono, fontSize: 9, color: T.textMute, letterSpacing: "0.06em", padding: "3px 6px", border: `1px solid ${T.borderSoft}` }}>
                    {k.toUpperCase()}
                  </span>
                ))}
              </div>
            </div>
          )}
        </Section>

        {p.tier && (
          <Section title="Model Output">
            <div style={{ display: "grid", gap: 10 }}>
              <Row k="Tier" v={p.tier} />
              <Row k="Personal Score" v={displayScore(p) != null ? displayScore(p).toFixed(2) : "—"} />
              <Row k="Percentile" v={p.percentile != null ? `${p.percentile}` : "—"} />
            </div>
            {/* Weighted Trait + Risk Penalty used to render here. They're
                pipeline intermediates rather than scout-readable signals —
                a percentile + a tier already encode their effect. Removed
                from the surface to keep Model Output focused. */}
          </Section>
        )}
      </div>
    </div>
  );
};

